    @Test("all toggles off yields nil segment")
    func allOff() {
        let segment = resolveWith(TimeWindowDisplay(
            showDot: false, showLetter: false, letter: "S",
            showPercent: false, showReset: false
        ))
        #expect(segment == nil)
    }
}

